#include<bits/stdc++.h>
using namespace std;
int dx[4]={1,0,-1,0};
int dy[4]={0,1,0,-1};//右下左上 
int bz[105][105],num=0;
long long tot=0,e[10],f[10];
int a,b,c,d,t,n,m;
void dfs(int p,int q)
{	 
	int x,y;
	bz[p][q]=0;
	for(int i=0;i<=3;i++)
	{
		x=p+dx[i];
		y=q+dy[i]; 
		if(x>=1&&x<=m&&y>=1&&y<=n&&bz[x][y])
		{	
			if(x==c&&y==d)
			{
				tot++;
				return ;
			}
			dfs(x,y);
			bz[x][y]=1;
		}
	}
}
int main()
{
	for(int i=1;i<=105;i++)
	{
		for(int j=1;j<=105;j++)
		{
			bz[i][j]=1;
		}
	}
	scanf("%d%d%d%d%d%d%d",&n,&m,&t,&a,&b,&c,&d);
	for(int i=1;i<=t;i++)
	{
		scanf("%d%d",&e[i],&f[i]);
		bz[e[i]][f[i]]=0;
	}
	dfs(a,b);
	printf("%lld",tot-1);
	return 0;
}
